fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut dp = vec![vec![vec![0; 3]; 2]; 1 << n];

    for mask in 0..(1 << n) {
        for i in 0..n {
            if (mask & (1 << i)) == 0 {
                continue;
            }
            let mut new_mask = mask ^ (1 << i);
            for j in 0..3 {
                dp[mask][i][j] = dp[new_mask][i - 1][j];
            }
            if j == 0 {
                dp[mask][i][0] = dp[new_mask][i - 1][0] ^ nums[i];
            } else if j == 1 {
                dp[mask][i][1] = dp[new_mask][i - 1][1] & nums[i];
            } else {
                dp[mask][i][2] = dp[new_mask][i - 1][2] ^ nums[i];
            }
        }
    }

    let mut max_val = 0;
    for i in 0..n {
        for j in 0..3 {
            max_val = std::cmp::max(max_val, dp[(1 << n) - 1][n - 1][j]);
        }
    }

    max_val
}
