fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut dp = vec![vec![vec![0; 3]; 2]; 1 << n];

    for mask in 0..(1 << n) {
        for i in 0..n {
            if (mask & (1 << i)) == 0 {
                continue;
            }
            let mut new_dp = vec![vec![0; 3]; 2];
            for a in 0..2 {
                for b in 0..2 {
                    for c in 0..2 {
                        if a + b + c == 3 {
                            let val = nums[i];
                            let mut xor_a = 0;
                            let mut and_b = 0;
                            let mut xor_c = 0;
                            if a == 0 {
                                xor_a = val;
                            } else if a == 1 {
                                xor_a = dp[mask ^ (1 << i)][0][0] ^ val;
                            } else {
                                xor_a = dp[mask ^ (1 << i)][0][1] ^ val;
                            }
                            if b == 0 {
                                and_b = val;
                            } else if b == 1 {
                                and_b = dp[mask ^ (1 << i)][1][0] & val;
                            } else {
                                and_b = dp[mask ^ (1 << i)][1][1] & val;
                            }
                            if c == 0 {
                                xor_c = val;
                            } else if c == 1 {
                                xor_c = dp[mask ^ (1 << i)][2][0] ^ val;
                            } else {
                                xor_c = dp[mask ^ (1 << i)][2][1] ^ val;
                            }
                            new_dp[a][b] = std::cmp::max(new_dp[a][b], xor_a + and_b + xor_c);
                        }
                    }
                }
            }
            dp[mask] = new_dp;
        }
    }

    let mut max_val = 0;
    for a in 0..2 {
        for b in 0..2 {
            for c in 0..2 {
                if a + b + c == 3 {
                    max_val = std::cmp::max(max_val, dp[(1 << n) - 1][a][b]);
                }
            }
        }
    }
    max_val
}
