fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut dp = vec![vec![0; 1 << 30]; 1 << 30];

    for i in 0..n {
        let num = nums[i];
        for mask in 0..(1 << 30) {
            let mut new_mask = mask;
            let mut xor_a = 0;
            let mut and_b = 0;
            let mut xor_c = 0;

            // Try to assign to A
            if (mask & (1 << i)) == 0 {
                new_mask |= 1 << i;
                xor_a = num;
                and_b = 0;
                xor_c = 0;
            }

            // Try to assign to B
            if (mask & (1 << i)) == 0 {
                new_mask |= 1 << i;
                xor_a = 0;
                and_b = num;
                xor_c = 0;
            }

            // Try to assign to C
            if (mask & (1 << i)) == 0 {
                new_mask |= 1 << i;
                xor_a = 0;
                and_b = 0;
                xor_c = num;
            }

            dp[new_mask] = dp[mask].max(dp[new_mask]);
            dp[new_mask] = dp[new_mask].max(xor_a + and_b + xor_c);
        }
    }

    let mut max_val = 0;
    for mask in 0..(1 << 30) {
        max_val = max_val.max(dp[mask]);
    }

    max_val
}
