fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut dp = vec![vec![0; 1 << 30]; 1 << 30];

    for i in 0..n {
        for mask in 0..(1 << 30) {
            let mut new_mask = mask;
            let mut xor_a = 0;
            let mut and_b = 0;
            let mut xor_c = 0;

            // Try to assign current number to A, B, or C
            // Assign to A
            if (mask & (1 << i)) == 0 {
                let mut new_mask_a = mask | (1 << i);
                let mut xor_a_new = xor_a ^ nums[i];
                let mut and_b_new = and_b;
                let mut xor_c_new = xor_c;
                dp[new_mask_a][i + 1] = std::cmp::max(dp[new_mask_a][i + 1], xor_a_new + and_b_new + xor_c_new);
            }

            // Assign to B
            if (mask & (1 << i)) == 0 {
                let mut new_mask_b = mask | (1 << i);
                let mut xor_a_new = xor_a;
                let mut and_b_new = and_b & nums[i];
                let mut xor_c_new = xor_c;
                dp[new_mask_b][i + 1] = std::cmp::max(dp[new_mask_b][i + 1], xor_a_new + and_b_new + xor_c_new);
            }

            // Assign to C
            if (mask & (1 << i)) == 0 {
                let mut new_mask_c = mask | (1 << i);
                let mut xor_a_new = xor_a;
                let mut and_b_new = and_b;
                let mut xor_c_new = xor_c ^ nums[i];
                dp[new_mask_c][i + 1] = std::cmp::max(dp[new_mask_c][i + 1], xor_a_new + and_b_new + xor_c_new);
            }
        }
    }

    let mut max_val = 0;
    for i in 0..(1 << 30) {
        max_val = std::cmp::max(max_val, dp[i][n]);
    }
    max_val
}
