fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut dp = vec![vec![vec![0; 3]; 2]; 1 << n];

    for mask in 0..(1 << n) {
        let mut cnt = [0; 3];
        let mut xor_a = 0;
        let mut and_b = 0;
        let mut xor_c = 0;

        for i in 0..n {
            if (mask & (1 << i)) != 0 {
                cnt[0] += 1;
                xor_a ^= nums[i];
                cnt[1] += 1;
                and_b &= nums[i];
                cnt[2] += 1;
                xor_c ^= nums[i];
            }
        }

        dp[mask][0][0] = xor_a;
        dp[mask][0][1] = and_b;
        dp[mask][0][2] = xor_c;

        for i in 0..n {
            if (mask & (1 << i)) == 0 {
                let new_mask = mask | (1 << i);
                let mut new_cnt = cnt;
                let mut new_xor_a = xor_a;
                let mut new_and_b = and_b;
                let mut new_xor_c = xor_c;

                if new_cnt[0] == 0 {
                    new_xor_a = nums[i];
                } else {
                    new_xor_a ^= nums[i];
                }

                if new_cnt[1] == 0 {
                    new_and_b = nums[i];
                } else {
                    new_and_b &= nums[i];
                }

                if new_cnt[2] == 0 {
                    new_xor_c = nums[i];
                } else {
                    new_xor_c ^= nums[i];
                }

                new_cnt[0] += 1;
                new_cnt[1] += 1;
                new_cnt[2] += 1;

                dp[new_mask][0][0] = new_xor_a;
                dp[new_mask][0][1] = new_and_b;
                dp[new_mask][0][2] = new_xor_c;
            }
        }
    }

    let mut max_val = 0;
    for mask in 0..(1 << n) {
        let xor_a = dp[mask][0][0];
        let and_b = dp[mask][0][1];
        let xor_c = dp[mask][0][2];
        max_val = max_val.max(xor_a + and_b + xor_c);
    }

    max_val
}
